private class VerboseHttpLoggingInterceptor(
    private val enabledProvider: () -> Boolean,
    private val redactHeaders: Set<String>,
    private val redactJsonKeys: Set<String>,
    private val maxBodyChars: Int,
    private val logResponseBody: Boolean,
    private val logRequestBody: Boolean,
    private val logHeaders: Boolean
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val enabled = enabledProvider()
        val request = chain.request()
        if (!enabled) return chain.proceed(request)

        val requestId = UUID.randomUUID().toString().take(8)
        val startNs = System.nanoTime()

        val requestLog = buildString {
            append("HTTP[$requestId] --> ")
            append(request.method).append(" ").append(request.url)
            append("\nProtocol: ").append(chain.connection()?.protocol() ?: "unknown")
            if (logHeaders) append("\nRequest Headers:\n").append(formatHeaders(request.headers, redactHeaders))
            if (logRequestBody) {
                val bodyText = requestBodyToString(request, maxBodyChars)
                if (bodyText != null) append("\nRequest Body:\n").append(bodyText)
            }
        }
        Timber.v(requestLog)

        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)

            val responseLog = buildString {
                append("HTTP[$requestId] <-- ")
                append(response.code).append(" ").append(response.message)
                append(" (").append(tookMs).append("ms) ")
                append(request.method).append(" ").append(request.url)
                if (logHeaders) append("\nResponse Headers:\n").append(formatHeaders(response.headers, redactHeaders))
            }

            if (!logResponseBody) {
                Timber.v(responseLog)
                response
            } else {
                val (peekedText, newResponse) = peekAndRecreateResponseBody(response, maxBodyChars)
                val redacted = redactBodyIfJson(peekedText, redactJsonKeys)
                Timber.v(responseLog + "\nResponse Body:\n" + redacted)
                newResponse
            }
        } catch (t: Throwable) {
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            Timber.e(t, "HTTP[$requestId] !! FAILED (${tookMs}ms) ${request.method} ${request.url}")
            throw t
        }
    }

    private fun formatHeaders(headers: Headers, redactSet: Set<String>): String {
        val redactLower = redactSet.map { it.lowercase() }.toSet()
        val out = StringBuilder()
        for (i in 0 until headers.size) {
            val name = headers.name(i)
            val value = headers.value(i)
            val redacted = if (name.lowercase() in redactLower) "[REDACTED]" else value
            out.append(name).append(": ").append(redacted).append("\n")
        }
        return out.toString().trimEnd()
    }

    private fun requestBodyToString(request: Request, maxChars: Int): String? {
        val body = request.body ?: return null
        val copy = request.newBuilder().build()
        val buffer = Buffer()
        try {
            body.writeTo(buffer)
        } catch (_: Throwable) {
            return "[unavailable: body write failed]"
        }

        val contentType = body.contentType()
        if (!isPlaintext(buffer)) return "[binary ${contentType ?: "unknown"}; ${buffer.size} bytes]"

        val charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
        val text = try {
            buffer.clone().readString(charset)
        } catch (_: Throwable) {
            return "[unavailable: decode failed]"
        }

        val truncated = truncate(text, maxChars)
        val redacted = redactBodyIfJson(truncated, redactJsonKeys)
        return redacted
    }

    private fun peekAndRecreateResponseBody(response: Response, maxChars: Int): Pair<String, Response> {
        val body = response.body
        if (body == null) return "" to response

        val source = body.source()
        source.request(Long.MAX_VALUE)
        var buffer = source.buffer.clone()

        val contentEncoding = response.header("Content-Encoding") ?: ""
        if (contentEncoding.equals("gzip", ignoreCase = true)) {
            try {
                GzipSource(buffer.clone()).use { gz ->
                    val unzipped = Buffer()
                    unzipped.writeAll(gz)
                    buffer = unzipped
                }
            } catch (_: Throwable) {
                return "[unavailable: gzip decode failed]" to response
            }
        }

        val contentType = body.contentType()
        if (!isPlaintext(buffer)) {
            val size = min(buffer.size, maxChars.toLong())
            val bytes = buffer.clone().readByteArray(size)
            val hash = sha256Short(bytes)
            val msg = "[binary ${contentType ?: "unknown"}; size=${buffer.size} bytes; sha256_12=$hash]"
            return msg to response
        }

        val charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
        val text = try {
            buffer.clone().readString(charset)
        } catch (_: Throwable) {
            "[unavailable: decode failed]"
        }

        val truncated = truncate(text, maxChars)
        val rebuiltBody = ResponseBody.create(body.contentType(), body.bytes())
        val newResponse = response.newBuilder().body(rebuiltBody).build()
        return truncated to newResponse
    }

    private fun redactBodyIfJson(body: String, redactKeys: Set<String>): String {
        val trimmed = body.trim()
        val likelyJson = (trimmed.startsWith("{") && trimmed.endsWith("}")) ||
            (trimmed.startsWith("[") && trimmed.endsWith("]")) ||
            (trimmed.startsWith("{") || trimmed.startsWith("["))
        if (!likelyJson) return body
        return JsonRedactor.redactJsonLike(body, redactKeys) { original ->
            if (original.isBlank()) original else "[REDACTED:${sha256Short(original)}]"
        }
    }

    private fun truncate(s: String, max: Int): String {
        if (max <= 0) return ""
        if (s.length <= max) return s
        return s.take(max) + "…(truncated,len=${s.length})"
    }

    private fun sha256Short(bytes: ByteArray): String {
        val md = MessageDigest.getInstance("SHA-256").digest(bytes)
        return md.joinToString("") { "%02x".format(it) }.take(12)
    }

    private fun sha256Short(input: String): String {
        val md = MessageDigest.getInstance("SHA-256").digest(input.toByteArray(Charsets.UTF_8))
        return md.joinToString("") { "%02x".format(it) }.take(12)
    }

    private fun isPlaintext(buffer: Buffer): Boolean {
        try {
            val prefix = Buffer()
            val byteCount = min(buffer.size, 64)
            buffer.copyTo(prefix, 0, byteCount)
            for (i in 0 until 16) {
                if (prefix.exhausted()) break
                val codePoint = prefix.readUtf8CodePoint()
                if (Character.isISOControl(codePoint) && !Character.isWhitespace(codePoint)) return false
            }
            return true
        } catch (_: EOFException) {
            return false
        }
    }
}

private object JsonRedactor {

    fun redactJsonLike(input: String, keysToRedact: Set<String>, replacement: (String) -> String): String {
        if (keysToRedact.isEmpty()) return input
        val keysLower = keysToRedact.map { it.lowercase() }.toSet()

        val sb = StringBuilder(input.length)
        var i = 0
        var inString = false
        var escape = false
        var expectingKeyOrValue = false
        var lastKey: String? = null
        var afterColon = false

        fun readString(startQuoteIndex: Int): Pair<String, Int> {
            val out = StringBuilder()
            var idx = startQuoteIndex + 1
            var esc = false
            while (idx < input.length) {
                val c = input[idx]
                if (esc) {
                    out.append(c)
                    esc = false
                } else if (c == '\\') {
                    esc = true
                    out.append(c)
                } else if (c == '"') {
                    return out.toString() to idx
                } else {
                    out.append(c)
                }
                idx++
            }
            return out.toString() to (input.length - 1)
        }

        while (i < input.length) {
            val c = input[i]
            if (!inString) {
                when (c) {
                    '"' -> {
                        inString = true
                        val (str, endIdx) = readString(i)
                        val full = input.substring(i, endIdx + 1)

                        if (!afterColon) {
                            lastKey = unescapeMinimal(str)
                            expectingKeyOrValue = true
                            sb.append(full)
                        } else {
                            val key = lastKey?.lowercase()
                            if (key != null && key in keysLower) {
                                val originalValue = unescapeMinimal(str)
                                val repl = replacement(originalValue)
                                sb.append('"').append(escapeJsonString(repl)).append('"')
                            } else {
                                sb.append(full)
                            }
                            afterColon = false
                        }

                        i = endIdx
                        inString = false
                    }
                    ':' -> {
                        afterColon = true
                        sb.append(c)
                    }
                    '{', '[', '}', ']', ',', ' ', '\n', '\r', '\t' -> {
                        sb.append(c)
                    }
                    else -> {
                        if (afterColon) {
                            val key = lastKey?.lowercase()
                            if (key != null && key in keysLower) {
                                val (token, end) = readNonStringToken(input, i)
                                val repl = replacement(token)
                                sb.append('"').append(escapeJsonString(repl)).append('"')
                                i = end
                                afterColon = false
                            } else {
                                sb.append(c)
                            }
                        } else {
                            sb.append(c)
                        }
                    }
                }
            } else {
                sb.append(c)
            }
            i++
        }

        return sb.toString()
    }

    private fun readNonStringToken(s: String, start: Int): Pair<String, Int> {
        var i = start
        while (i < s.length) {
            val c = s[i]
            if (c == ',' || c == '}' || c == ']' || c == '\n' || c == '\r' || c == '\t' || c == ' ') break
            i++
        }
        val token = s.substring(start, i)
        return token to (i - 1)
    }

    private fun escapeJsonString(s: String): String {
        val sb = StringBuilder(s.length + 16)
        for (c in s) {
            when (c) {
                '\\' -> sb.append("\\\\")
                '"' -> sb.append("\\\"")
                '\b' -> sb.append("\\b")
                '\u000C' -> sb.append("\\f")
                '\n' -> sb.append("\\n")
                '\r' -> sb.append("\\r")
                '\t' -> sb.append("\\t")
                else -> {
                    if (c.code < 0x20) sb.append("\\u").append(c.code.toString(16).padStart(4, '0'))
                    else sb.append(c)
                }
            }
        }
        return sb.toString()
    }

    private fun unescapeMinimal(s: String): String {
        return s.replace("\\\"", "\"").replace("\\\\", "\\")
    }
}

class LoggingUncaughtExceptionHandler(
    private val delegate: Thread.UncaughtExceptionHandler? = Thread.getDefaultUncaughtExceptionHandler()
) : Thread.UncaughtExceptionHandler {
    override fun uncaughtException(t: Thread, e: Throwable) {
        try {
            AppLogging.Crash.log(e, message = "UncaughtException thread=${t.name}")
        } catch (_: Throwable) {
        } finally {
            delegate?.uncaughtException(t, e)
        }
    }
}

object LoggingInstallers {
    fun installUncaughtExceptionHandler() {
        Thread.setDefaultUncaughtExceptionHandler(LoggingUncaughtExceptionHandler())
    }
}